        if (root.PF) {
            return Object.keys(root.PF).filter(function(name) {
                return (/Finder$/.test(name) || /^JPF/.test(name)) &&
                    name !== 'JumpPointFinderBase';
            }).sort();
        }

        return [];
    }

function parseGridSize(value) {
    var match = /^\s*(\d+)\s*[xX]\s*(\d+)\s*$/.exec(value || '');

    if (!match) {
        return DEFAULT_GRID_SIZE.slice();
    }

    return [parseInt(match[1], 10), parseInt(match[2], 10)];
}

function parseNumber(value) {
    var parsed = parseInt(value, 10);
    return isFinite(parsed) ? parsed : null;
}

function parseSpeed(value, minSpeed, maxSpeed) {
    var min = parseNumber(minSpeed);
    var max = parseNumber(maxSpeed);
    var speed = parseInt(value, 10);

    if (!isFinite(speed)) {
        return DEFAULT_SPEED;
    }

    if (min === null) {
        min = MIN_SPEED;
    }
    if (max === null) {
        max = MAX_SPEED;
    }

    return Math.max(min, Math.min(max, speed));
}

    function addListener(collection, listener) {
        if (typeof listener === 'function') {
            collection.push(listener);
        }
    }

    function create(options) {
        var findPathListeners = [];
        var clearListeners = [];
        var speedValueElement = options.speedValueElement;

        function renderSpeedValue() {
            if (!speedValueElement) {
                return;
            }
            speedValueElement.textContent = String(parseSpeed(
                options.speedInput.value,
                options.speedInput.min,
                options.speedInput.max
            ));
        }

        options.findPathButton.addEventListener('click', function() {
            findPathListeners.forEach(function(listener) {
                listener();
            });
        });

        options.clearButton.addEventListener('click', function() {
            clearListeners.forEach(function(listener) {
                listener();
            });
        });

        options.speedInput.addEventListener('input', renderSpeedValue);
        renderSpeedValue();

