'use strict';

var scorer = require('./scorer');
var persistence = require('./persistence');
var createScenarioBuilder = require('./scenario-builder');
var createScenarioRuntime = require('./runtime');
var controls = require('./controls');

module.exports = {
    createScenarioBuilder: createScenarioBuilder,
    createScenarioRuntime: createScenarioRuntime,
    createScenarioControls: controls.create,
    discoverAlgorithms: controls.discoverAlgorithms,

    captureMetrics: scorer.captureMetrics,
    saveRun: scorer.saveRun,
    getSavedRuns: scorer.getSavedRuns,
    clearRuns: scorer.clearRuns,
    compareRuns: scorer.compareRuns,

    saveScenario: persistence.saveScenario,
    loadScenario: persistence.loadScenario,
    getPresets: persistence.getPresets,
    loadPreset: persistence.loadPreset
};

(function(root, factory) {
