        module.exports = factory;
    } else {
        root.createScenarioApp = factory;

        if (root.document) {
            if (root.document.readyState === 'loading') {
                root.document.addEventListener('DOMContentLoaded', function() {
                    factory({ root: root });
                });
            } else {
                factory({ root: root });
            }
        }
    }
}(typeof window !== 'undefined' ? window : this, function(options) {
