            var id = ids[i];
            var el = doc.getElementById(id);

            if (!el) {
                return null;
            }
            elements[id] = el;
        }

        return elements;
    }

    var elements = getRequiredElements([
        'grid',
        'status',
        'metrics',
        'scenario-data',
        'preset-select',
        'runs-list',
        'comparison-results',
        'comparison-drawer',
        'algorithm-select',
        'grid-size-select',
        'speed-input',
        'speed-value',
        'find-path',
        'clear-grid',
        'mode-wall',
        'mode-start',
        'mode-end',
        'save-scenario',
        'load-scenario',
        'save-run',
        'compare-selected',
        'clear-saved-runs',
        'open-comparison'
    ]);

    if (!elements) {
        return null;
    }

    var runtime = runtimeFactory();
    var builder = builderFactory({ width: 15, height: 15 });
    var mode = 'wall';
    var animationTimer = null;
    var lastRun = null;
    var animated = {
        explored: {},
        path: {}
    };

    var gridElement = elements.grid;
    var statusElement = elements.status;
    var metricsElement = elements.metrics;
    var scenarioDataElement = elements['scenario-data'];
    var presetSelect = elements['preset-select'];
    var runsListElement = elements['runs-list'];
    var comparisonElement = elements['comparison-results'];
    var comparisonDrawer = elements['comparison-drawer'];

    var buttons = {
        wall: elements['mode-wall'],
        start: elements['mode-start'],
        end: elements['mode-end']
