    var controls = controlsModule.create({
        algorithmSelect: elements['algorithm-select'],
        gridSizeSelect: elements['grid-size-select'],
        speedInput: elements['speed-input'],
        speedValueElement: elements['speed-value'],
        findPathButton: elements['find-path'],
        clearButton: elements['clear-grid']
    });

    function key(x, y) {
        return x + ',' + y;
    }

    function clearAnimation() {
        if (animationTimer !== null) {
            clearInterval(animationTimer);
            animationTimer = null;
        }
        animated.explored = {};
        animated.path = {};
