    function updateMetrics(metrics) {
        if (!metrics) {
            metricsElement.innerHTML = '';
            return;
        }

        metricsElement.innerHTML = [
            '<div class="metric"><strong>Nodes explored</strong><span>' + metrics.nodesExplored + '</span></div>',
            '<div class="metric"><strong>Path length</strong><span>' + metrics.pathLength + '</span></div>',
            '<div class="metric"><strong>Time</strong><span>' + metrics.timeMs + ' ms</span></div>'
        ].join('');
    }

    function render() {
        var grid = builder.getGrid();
        var start = builder.getStart();
        var end = builder.getEnd();
        var height = grid.length;
        var width = grid[0].length;

        gridElement.innerHTML = '';
        gridElement.style.gridTemplateColumns = 'repeat(' + width + ', 1fr)';
        gridElement.style.gridTemplateRows = 'repeat(' + height + ', 1fr)';

        for (var y = 0; y < height; y += 1) {
            for (var x = 0; x < width; x += 1) {
                (function(cx, cy) {
