                    if (animated.explored[cellKey]) {
                        cell.classList.add('explored');
                    }
                    if (animated.path[cellKey]) {
                        cell.classList.add('path');
                    }
                    if (start.x === cx && start.y === cy) {
                        cell.classList.add('start');
                    }
                    if (end.x === cx && end.y === cy) {
                        cell.classList.add('end');
