    function mapStateFromBuilder() {
        return runtime.gridToScenario(
            builder.getGrid(),
            builder.getStart(),
            builder.getEnd()
        );
    }

    function animateRun(result) {
        clearAnimation();

        var sequence = [];
        var i;

        for (i = 0; i < result.exploredNodes.length; i += 1) {
            sequence.push({
                phase: 'explored',
                point: result.exploredNodes[i]
            });
        }

        for (i = 0; i < result.path.length; i += 1) {
            sequence.push({
                phase: 'path',
                point: result.path[i]
            });
        }

        if (!sequence.length) {
            render();
            return;
        }

        var speed = controls.getSpeed();
        var stepMs = Math.max(16, Math.floor(speed / Math.max(10, sequence.length)));
        var index = 0;

        animationTimer = setInterval(function() {
            var step = sequence[index];
            if (!step) {
                clearInterval(animationTimer);
                animationTimer = null;
                return;
            }

            var stepKey = key(step.point[0], step.point[1]);
            if (step.phase === 'explored') {
                animated.explored[stepKey] = true;
            } else {
                animated.path[stepKey] = true;
            }

            index += 1;
            render();

            if (index >= sequence.length) {
                clearInterval(animationTimer);
                animationTimer = null;
            }
        }, stepMs);
    }

    function setMode(nextMode) {
        mode = nextMode;
        statusElement.textContent = 'Mode: ' + mode;

        Object.keys(buttons).forEach(function(name) {
            if (name === mode) {
                buttons[name].classList.add('is-active');
            } else {
                buttons[name].classList.remove('is-active');
            }
        });
    }

    function rerenderSavedRuns() {
        var runs = runtime.getSavedRuns();

        if (!runs.length) {
            runsListElement.innerHTML = '<p class="muted">No saved runs yet.</p>';
            return;
        }

        runsListElement.innerHTML = runs.map(function(run) {
            return '<label class="saved-run">' +
                '<input type="checkbox" data-run-id="' + run.id + '">' +
                '<span>#' + run.id + ' ' + run.algorithm +
                ' · explored ' + run.metrics.nodesExplored +
                ' · path ' + run.metrics.pathLength +
                ' · ' + run.metrics.timeMs + 'ms</span>' +
                '</label>';
        }).join('');
    }

    function renderComparison(comparison) {
        var baseId = comparison.baseRunId;
        var baseRun = null;
        var columns = [];
        var html;

        comparison.runs.forEach(function(run) {
            if (run.id === baseId) {
                baseRun = run;
                return;
            }
            columns.push(run);
        });

        if (!baseRun) {
            comparisonElement.textContent = 'Base run not found for comparison';
            return;
        }

        html = [
            '<div class="comparison-grid" style="--comparison-cols:' + (columns.length + 1) + ';">',
            '<div class="comparison-card is-base">',
            '<h4>#' + baseRun.id + ' (' + baseRun.algorithm + ')</h4>',
            '<div class="metric-line"><span>Nodes</span><strong>' + baseRun.metrics.nodesExplored + '</strong></div>',
            '<div class="metric-line"><span>Path</span><strong>' + baseRun.metrics.pathLength + '</strong></div>',
            '<div class="metric-line"><span>Time</span><strong>' + baseRun.metrics.timeMs + ' ms</strong></div>',

            '<div class="metric-line"><span>Time</span><strong>' + baseRun.metrics.timeMs + ' ms</strong></div>',
            '</div>'
        ];

        columns.forEach(function(run) {
