                '<div class="metric-line"><span>Time</span><strong>' + run.metrics.timeMs + ' ms</strong></div>' +
                '<div class="metric-diff">Δ ' + (diff.timeMs >= 0 ? '+' : '') + diff.timeMs + ' ms</div>' +
                '</div>'
